import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 金剛鎖 } from '../bujian/sanmaya.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛鎖尊 = (bi) => 菩薩坐身(bi, {
    臂(bi, 筆) {
        const { 骨, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊右：鎖鏈豎執於體側（鏈先落，拳覆下端三鈷之柄）
        金剛鎖(bi, -8.6, 32.6, 0.78);
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.2], [-10.3, 38.9], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.3, 肘帽: true })));
        側拳(bi, -8.6, 37.6, 2.05, 1.05);
        // 尊左：拳安腰際
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [13.0, 45.6], { 寬根: 2.4, 寬梢: 1.8, 弓: -0.3, 肘帽: false })));
        側拳(bi, 12.8, 47.9, Math.PI / 2, 1.05, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-11.5, 38.5, -10.7, 39.2, -9.9, 39.9], [-11.1, 39.4, -10.3, 40.1, -9.5, 40.8]], [-10.6, 39.6]);
            腕釧(bi, [[11.9, 44.9, 13.0, 45.4, 14.1, 45.0], [11.8, 45.8, 12.9, 46.3, 14.0, 45.9]], [12.9, 45.8]);
        });
    },
});
